//! fat-station-uds-zerocopy — SCM_RIGHTS variant of fat-station-uds.
//!
//! Why this exists
//! ----------------
//! The framed UDS path (`fat-station-uds.rs`) still copies residual bytes
//! sender→kernel→receiver buffer on every call. For Pneuma's per-token
//! autoregressive loop with `hidden_dim=3584` (~14 KiB residual at
//! seq_len=1, ~115 KiB at seq_len=8) × N layers × N stations × 256
//! generated tokens per turn, that's MB-scale memory bandwidth burned on
//! memcpys we don't need.
//!
//! The kernel is Apple/Linux: a Unix socket can carry an open file
//! descriptor as ancillary data via `SCM_RIGHTS`. Recipe per call:
//!
//!   1. Sender creates an "anonymous" shared mmap (Linux: `memfd_create`,
//!      Darwin: `shm_open` + immediate `shm_unlink` so the name dies but
//!      the fd lives).
//!   2. Sender `ftruncate`s to residual length, mmaps RW, writes the
//!      residual bytes directly into shared memory.
//!   3. Sender `sendmsg`s the small ASCII control frame (length-prefix +
//!      headers, NO body) WITH the mmap fd attached as SCM_RIGHTS.
//!   4. Receiver `recvmsg`s, picks the fd out of the cmsg, mmaps it
//!      read-only, slices f32s — zero copy between processes.
//!   5. Receiver runs the kernel, allocates a NEW mmap, writes the
//!      response into it, sends back the response fd via SCM_RIGHTS.
//!
//! Wire format
//! -----------
//! Same length-prefixed ASCII headers as fat-station-uds, with these
//! pseudo-headers added:
//!
//!   X-ZC-Body-Bytes: 459776     <- byte length of the residual in shm
//!   X-ZC-Body-Format: f32       <- "f32" or "u32"
//!
//! The data frame body is empty — payload is in the attached fd. Reading
//! a frame:
//!
//!   * `recvmsg` with control buffer sized for one fd
//!   * 4-byte BE u32 length prefix from the data buffer
//!   * ASCII headers up to "\n\n"
//!   * data buffer body length must equal 0 (X-ZC-Body-Bytes lives in
//!     the shm fd attached as SCM_RIGHTS)
//!
//! Roles
//! -----
//! Same surface as fat-station-uds: entry / exit / cobordism. The code
//! path differs only at the body codec: instead of decoding `frame.body`
//! bytes, we mmap the attached fd and view it as the requested format.
//!
//! Build:
//!   cd open-source/gnosis/distributed-inference
//!   cargo build --release --bin fat-station-uds-zerocopy
//!
//! See: docs/pneuma/uds-zerocopy.md

use std::io::{Read, Write};
use std::os::fd::{AsRawFd, FromRawFd, IntoRawFd, OwnedFd, RawFd};
use std::os::unix::net::{UnixListener, UnixStream};
use std::path::PathBuf;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::{Arc, Mutex};

use distributed_inference::model::NativeLlamaPipeline;
use memmap2::{Mmap, MmapOptions};

const NATIVE_BATCH_CAPACITY: usize = 8;
const MAX_DATA_FRAME: usize = 64 * 1024; // headers only, no body — 64 KiB is huge
const MAX_BODY_BYTES: usize = 256 * 1024 * 1024;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Role {
    Entry,
    Mid,
    Exit,
    Both,
    Cobordism,
}

impl Role {
    fn parse(s: &str) -> Result<Self, String> {
        match s.to_lowercase().as_str() {
            "entry" => Ok(Role::Entry),
            "mid" => Ok(Role::Mid),
            "exit" => Ok(Role::Exit),
            "both" => Ok(Role::Both),
            "cobordism" => Ok(Role::Cobordism),
            other => Err(format!(
                "--role must be entry|mid|exit|both|cobordism (got '{}')",
                other
            )),
        }
    }
    fn as_str(self) -> &'static str {
        match self {
            Role::Entry => "entry",
            Role::Mid => "mid",
            Role::Exit => "exit",
            Role::Both => "both",
            Role::Cobordism => "cobordism",
        }
    }
}

#[derive(Debug)]
struct Cli {
    knot: String,
    sock: PathBuf,
    role: Role,
    layers: (usize, usize),
    vocab: Option<(usize, usize)>,
}

fn parse_range(arg: &str, name: &str) -> Result<(usize, usize), String> {
    let sep = if arg.contains("..") { ".." } else { ":" };
    let (a, b) = arg
        .split_once(sep)
        .ok_or_else(|| format!("{}: expected 'start..end' (got '{}')", name, arg))?;
    let start: usize = a
        .parse()
        .map_err(|e| format!("{}: bad start '{}': {}", name, a, e))?;
    let end: usize = b
        .parse()
        .map_err(|e| format!("{}: bad end '{}': {}", name, b, e))?;
    if end < start {
        return Err(format!(
            "{}: end must be >= start ({} < {})",
            name, end, start
        ));
    }
    Ok((start, end))
}

fn parse_cli() -> Result<Cli, String> {
    let mut args = std::env::args().skip(1);
    let mut knot: Option<String> = None;
    let mut sock: Option<PathBuf> = None;
    let mut role: Option<Role> = None;
    let mut layers: Option<(usize, usize)> = None;
    let mut vocab: Option<(usize, usize)> = None;
    while let Some(a) = args.next() {
        match a.as_str() {
            "--knot" => knot = Some(args.next().ok_or("--knot requires a value")?),
            "--sock" => sock = Some(PathBuf::from(args.next().ok_or("--sock requires a value")?)),
            "--role" => role = Some(Role::parse(&args.next().ok_or("--role requires a value")?)?),
            "--layers" => {
                layers = Some(parse_range(
                    &args.next().ok_or("--layers requires a value")?,
                    "--layers",
                )?)
            }
            "--vocab" => {
                vocab = Some(parse_range(
                    &args.next().ok_or("--vocab requires a value")?,
                    "--vocab",
                )?)
            }
            "--help" | "-h" => {
                print_usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown arg: {}", other)),
        }
    }
    let knot = knot.ok_or("--knot is required")?;
    let sock = sock.ok_or("--sock is required")?;
    let role = role.ok_or("--role is required")?;
    let layers = layers.unwrap_or((0, 0));
    if role == Role::Cobordism && vocab.is_none() {
        return Err("--vocab is required when --role=cobordism".to_string());
    }
    Ok(Cli {
        knot,
        sock,
        role,
        layers,
        vocab,
    })
}

fn print_usage() {
    eprintln!(
        "fat-station-uds-zerocopy --knot PATH --sock PATH \\\n  \
         --role {{entry|mid|exit|both|cobordism}} \\\n  \
         --layers START..END [--vocab START..END]\n\n\
         Wire: 4-byte BE length prefix + ASCII headers (no body bytes); \n  \
         payload travels as an SCM_RIGHTS-attached mmap fd.\n\n\
         Body-fd headers:  X-ZC-Body-Bytes  X-ZC-Body-Format (f32|u32)"
    );
}

// ─────────────────────────────────────────────────────────────────────
// Cross-platform anonymous shared-memory fd
// ─────────────────────────────────────────────────────────────────────
//
// Linux:  memfd_create(name, MFD_CLOEXEC) — pure anonymous, no namespace.
// Darwin: shm_open(name, O_RDWR|O_CREAT|O_EXCL, 0600) then immediate
//         shm_unlink(name) — the name is gone from the namespace but
//         the fd is still open and ftruncatable.
//
// On both, the resulting fd is a regular ftruncate-able / mmap-able
// file descriptor that survives a sendmsg(SCM_RIGHTS) crossing.

#[cfg(target_os = "linux")]
fn open_anon_shm(name: &str, size: usize) -> std::io::Result<OwnedFd> {
    use std::ffi::CString;
    let cname = CString::new(name).unwrap();
    // memfd_create syscall — libc 0.2 exposes it on Linux
    let fd = unsafe { libc::memfd_create(cname.as_ptr(), libc::MFD_CLOEXEC) };
    if fd < 0 {
        return Err(std::io::Error::last_os_error());
    }
    if unsafe { libc::ftruncate(fd, size as libc::off_t) } < 0 {
        let e = std::io::Error::last_os_error();
        unsafe {
            libc::close(fd);
        }
        return Err(e);
    }
    Ok(unsafe { OwnedFd::from_raw_fd(fd) })
}

#[cfg(target_os = "macos")]
fn open_anon_shm(name: &str, size: usize) -> std::io::Result<OwnedFd> {
    use std::ffi::CString;
    // POSIX shm names on Darwin must start with '/' and be unique.
    static COUNTER: AtomicU64 = AtomicU64::new(0);
    let n = COUNTER.fetch_add(1, Ordering::Relaxed);
    let pid = unsafe { libc::getpid() };
    let unique = format!("/zc-{}-{}-{}-{}", name, pid, std::process::id(), n);
    let cname = CString::new(unique.as_str()).unwrap();
    let fd = unsafe {
        libc::shm_open(
            cname.as_ptr(),
            libc::O_RDWR | libc::O_CREAT | libc::O_EXCL,
            0o600 as libc::c_uint,
        )
    };
    if fd < 0 {
        return Err(std::io::Error::last_os_error());
    }
    // Unlink immediately — the fd reference keeps the segment alive,
    // but the name disappears from /tmp/<shm-namespace>. Anonymous-ish.
    unsafe {
        libc::shm_unlink(cname.as_ptr());
    }
    if unsafe { libc::ftruncate(fd, size as libc::off_t) } < 0 {
        let e = std::io::Error::last_os_error();
        unsafe {
            libc::close(fd);
        }
        return Err(e);
    }
    // Set CLOEXEC by hand (shm_open doesn't take O_CLOEXEC on older Darwin).
    unsafe {
        let flags = libc::fcntl(fd, libc::F_GETFD);
        if flags >= 0 {
            libc::fcntl(fd, libc::F_SETFD, flags | libc::FD_CLOEXEC);
        }
    }
    Ok(unsafe { OwnedFd::from_raw_fd(fd) })
}

// ─────────────────────────────────────────────────────────────────────
// sendmsg / recvmsg with SCM_RIGHTS
// ─────────────────────────────────────────────────────────────────────
//
// We send/receive a single iov + (optionally) one ancillary fd.
// The control buffer is sized for exactly one fd, computed via
// `CMSG_SPACE(size_of::<RawFd>())`.

fn send_with_fd(stream: &UnixStream, data: &[u8], fd: Option<RawFd>) -> std::io::Result<()> {
    unsafe {
        let mut iov = libc::iovec {
            iov_base: data.as_ptr() as *mut libc::c_void,
            iov_len: data.len(),
        };

        // Allocate cmsg buffer big enough for one fd. CMSG_SPACE pads to
        // the platform alignment boundary.
        let cmsg_space = libc::CMSG_SPACE(std::mem::size_of::<RawFd>() as u32) as usize;
        let mut cmsg_buf = vec![0u8; cmsg_space];

        let mut msg: libc::msghdr = std::mem::zeroed();
        msg.msg_iov = &mut iov;
        msg.msg_iovlen = 1;
        if fd.is_some() {
            msg.msg_control = cmsg_buf.as_mut_ptr() as *mut libc::c_void;
            msg.msg_controllen = cmsg_space as _;
        }

        if let Some(rawfd) = fd {
            let cmsg = libc::CMSG_FIRSTHDR(&msg);
            if cmsg.is_null() {
                return Err(std::io::Error::other(
                    "CMSG_FIRSTHDR returned null",
                ));
            }
            (*cmsg).cmsg_level = libc::SOL_SOCKET;
            (*cmsg).cmsg_type = libc::SCM_RIGHTS;
            (*cmsg).cmsg_len = libc::CMSG_LEN(std::mem::size_of::<RawFd>() as u32) as _;
            std::ptr::copy_nonoverlapping(
                &rawfd as *const RawFd as *const u8,
                libc::CMSG_DATA(cmsg),
                std::mem::size_of::<RawFd>(),
            );
        }

        // MSG_NOSIGNAL prevents SIGPIPE — we want EPIPE returned instead.
        let flags = if cfg!(target_os = "linux") {
            libc::MSG_NOSIGNAL
        } else {
            0
        };
        let n = libc::sendmsg(stream.as_raw_fd(), &msg, flags);
        if n < 0 {
            return Err(std::io::Error::last_os_error());
        }
        if n as usize != data.len() {
            return Err(std::io::Error::new(
                std::io::ErrorKind::WriteZero,
                format!("partial sendmsg: {} of {} bytes", n, data.len()),
            ));
        }
        Ok(())
    }
}

/// Returns (data_bytes, optional_fd). Reads a single sendmsg payload.
fn recv_with_fd(
    stream: &UnixStream,
    max_data: usize,
) -> std::io::Result<(Vec<u8>, Option<OwnedFd>)> {
    unsafe {
        let mut data = vec![0u8; max_data];
        let mut iov = libc::iovec {
            iov_base: data.as_mut_ptr() as *mut libc::c_void,
            iov_len: data.len(),
        };
        let cmsg_space = libc::CMSG_SPACE(std::mem::size_of::<RawFd>() as u32) as usize;
        let mut cmsg_buf = vec![0u8; cmsg_space];
        let mut msg: libc::msghdr = std::mem::zeroed();
        msg.msg_iov = &mut iov;
        msg.msg_iovlen = 1;
        msg.msg_control = cmsg_buf.as_mut_ptr() as *mut libc::c_void;
        msg.msg_controllen = cmsg_space as _;

        let n = libc::recvmsg(stream.as_raw_fd(), &mut msg, 0);
        if n < 0 {
            return Err(std::io::Error::last_os_error());
        }
        data.truncate(n as usize);

        let mut fd_out: Option<OwnedFd> = None;
        if !msg.msg_control.is_null() && (msg.msg_controllen as usize) >= cmsg_space {
            let cmsg = libc::CMSG_FIRSTHDR(&msg);
            if !cmsg.is_null()
                && (*cmsg).cmsg_level == libc::SOL_SOCKET
                && (*cmsg).cmsg_type == libc::SCM_RIGHTS
            {
                let mut rawfd: RawFd = -1;
                std::ptr::copy_nonoverlapping(
                    libc::CMSG_DATA(cmsg),
                    &mut rawfd as *mut RawFd as *mut u8,
                    std::mem::size_of::<RawFd>(),
                );
                if rawfd >= 0 {
                    fd_out = Some(OwnedFd::from_raw_fd(rawfd));
                }
            }
        }
        Ok((data, fd_out))
    }
}

// ─────────────────────────────────────────────────────────────────────
// Frame parsing (data side)
// ─────────────────────────────────────────────────────────────────────

#[derive(Debug)]
struct Frame {
    method: String,
    path: String,
    headers: Vec<(String, String)>,
    body_bytes: usize,
    #[allow(dead_code)]
    body_format: BodyFormat,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum BodyFormat {
    F32,
    U32,
    Empty,
}

impl Frame {
    fn header(&self, name: &str) -> Option<&str> {
        let target = name.to_ascii_lowercase();
        for (k, v) in &self.headers {
            if k.to_ascii_lowercase() == target {
                return Some(v.as_str());
            }
        }
        None
    }
}

fn parse_frame(buf: &[u8]) -> Result<Frame, String> {
    parse_frame_inner(buf, /* require_method_path */ true)
}

fn parse_response_frame(buf: &[u8]) -> Result<Frame, String> {
    // Responses carry "status: NNN" instead of method/path. Allow that.
    parse_frame_inner(buf, false)
}

fn parse_frame_inner(buf: &[u8], require_method_path: bool) -> Result<Frame, String> {
    if buf.len() < 4 {
        return Err("frame: shorter than 4-byte length prefix".into());
    }
    let total_len = u32::from_be_bytes([buf[0], buf[1], buf[2], buf[3]]) as usize;
    if total_len == 0 || total_len > MAX_DATA_FRAME {
        return Err(format!("frame: total_len {} out of bounds", total_len));
    }
    if buf.len() < 4 + total_len {
        return Err(format!(
            "frame: data short ({} bytes, need {})",
            buf.len(),
            4 + total_len
        ));
    }
    let frame = &buf[4..4 + total_len];
    let split = frame
        .windows(2)
        .position(|w| w == b"\n\n")
        .ok_or("frame: missing blank-line separator")?;
    let header_str = std::str::from_utf8(&frame[..split])
        .map_err(|e| format!("frame: headers not utf8: {}", e))?;

    let mut method = String::new();
    let mut path = String::new();
    let mut body_bytes: usize = 0;
    let mut body_format = BodyFormat::Empty;
    let mut headers: Vec<(String, String)> = Vec::new();
    for line in header_str.split('\n') {
        if line.is_empty() {
            continue;
        }
        let (k, v) = line
            .split_once(':')
            .ok_or_else(|| format!("malformed header: {:?}", line))?;
        let k = k.trim().to_string();
        let v = v.trim().to_string();
        match k.to_ascii_lowercase().as_str() {
            "method" => method = v,
            "path" => path = v,
            "x-zc-body-bytes" => {
                body_bytes = v.parse().map_err(|e| format!("X-ZC-Body-Bytes: {}", e))?
            }
            "x-zc-body-format" => {
                body_format = match v.to_ascii_lowercase().as_str() {
                    "f32" => BodyFormat::F32,
                    "u32" => BodyFormat::U32,
                    "u8" | "" | "empty" => BodyFormat::Empty,
                    other => return Err(format!("X-ZC-Body-Format: unknown '{}'", other)),
                }
            }
            _ => headers.push((k, v)),
        }
    }
    if require_method_path && (method.is_empty() || path.is_empty()) {
        return Err("frame missing method/path pseudo-headers".into());
    }
    if body_bytes > MAX_BODY_BYTES {
        return Err(format!(
            "X-ZC-Body-Bytes {} exceeds {}",
            body_bytes, MAX_BODY_BYTES
        ));
    }
    Ok(Frame {
        method,
        path,
        headers,
        body_bytes,
        body_format,
    })
}

fn build_data_frame(status: u16, extras: &[(&str, String)]) -> Vec<u8> {
    let mut hdrs = String::new();
    hdrs.push_str(&format!("status: {}\n", status));
    for (k, v) in extras {
        hdrs.push_str(&format!("{}: {}\n", k, v));
    }
    hdrs.push('\n');
    let bytes = hdrs.into_bytes();
    let total = bytes.len();
    let mut out = Vec::with_capacity(4 + total);
    out.extend_from_slice(&(total as u32).to_be_bytes());
    out.extend_from_slice(&bytes);
    out
}

// ─────────────────────────────────────────────────────────────────────
// Body view from attached fd (zero-copy)
// ─────────────────────────────────────────────────────────────────────

fn mmap_in_fd(fd: &OwnedFd, len: usize) -> Result<Mmap, String> {
    if len == 0 {
        // memmap2 doesn't allow 0-length maps. Caller should check.
        return Err("mmap_in_fd: zero length".into());
    }
    unsafe {
        MmapOptions::new()
            .len(len)
            .map(fd.as_raw_fd())
            .map_err(|e| format!("mmap rd: {}", e))
    }
}

fn fd_to_f32(fd: &OwnedFd, byte_len: usize) -> Result<Vec<f32>, String> {
    if !byte_len.is_multiple_of(4) {
        return Err(format!(
            "fd_to_f32: byte_len {} not a multiple of 4",
            byte_len
        ));
    }
    let m = mmap_in_fd(fd, byte_len)?;
    let n = byte_len / 4;
    let mut out = vec![0f32; n];
    // One memcpy from the shared mapping into the Vec we'll feed into the
    // kernel. This is the ONLY copy on the receive path and it could be
    // eliminated by handing the kernel a `&[f32]` view directly — that's
    // a future optimization. v1 keeps the kernel API unchanged.
    let src = m.as_ptr() as *const f32;
    unsafe {
        std::ptr::copy_nonoverlapping(src, out.as_mut_ptr(), n);
    }
    Ok(out)
}

fn fd_to_u32(fd: &OwnedFd, byte_len: usize) -> Result<Vec<u32>, String> {
    if !byte_len.is_multiple_of(4) {
        return Err(format!(
            "fd_to_u32: byte_len {} not a multiple of 4",
            byte_len
        ));
    }
    let m = mmap_in_fd(fd, byte_len)?;
    let n = byte_len / 4;
    let mut out = vec![0u32; n];
    let src = m.as_ptr() as *const u32;
    unsafe {
        std::ptr::copy_nonoverlapping(src, out.as_mut_ptr(), n);
    }
    Ok(out)
}

/// Allocate a fresh shm fd and copy `data` into it. Returns the fd and
/// the byte length so the response data frame can advertise it.
fn f32_to_fd(data: &[f32]) -> Result<(OwnedFd, usize), String> {
    let byte_len = data.len() * 4;
    if byte_len == 0 {
        // Allow empty by allocating one byte — receiver will see X-ZC-Body-Bytes=0.
        let fd = open_anon_shm("zc-out", 1).map_err(|e| format!("open shm out: {}", e))?;
        return Ok((fd, 0));
    }
    let fd = open_anon_shm("zc-out", byte_len).map_err(|e| format!("open shm out: {}", e))?;
    let mut m = unsafe {
        MmapOptions::new()
            .len(byte_len)
            .map_mut(fd.as_raw_fd())
            .map_err(|e| format!("mmap_mut out: {}", e))?
    };
    let dst = m.as_mut_ptr() as *mut f32;
    unsafe {
        std::ptr::copy_nonoverlapping(data.as_ptr(), dst, data.len());
    }
    drop(m);
    Ok((fd, byte_len))
}

// ─────────────────────────────────────────────────────────────────────
// Handlers (mirror fat-station-uds, just swap codecs)
// ─────────────────────────────────────────────────────────────────────

struct Station {
    pipeline: Mutex<NativeLlamaPipeline>,
    role: Role,
    layers: (usize, usize),
    vocab: Option<(usize, usize)>,
    vocab_size: usize,
    hidden_dim: usize,
}

fn parse_usize_header(frame: &Frame, name: &str) -> Result<usize, String> {
    let v = frame
        .header(name)
        .ok_or_else(|| format!("missing header: {}", name))?;
    v.parse::<usize>()
        .map_err(|e| format!("{}={:?}: {}", name, v, e))
}

fn parse_layer_range_header(frame: &Frame) -> Result<(usize, usize), String> {
    let raw = frame
        .header("X-Layer-Range")
        .ok_or("missing header: X-Layer-Range".to_string())?;
    let (a, b) = raw
        .split_once('-')
        .ok_or_else(|| format!("X-Layer-Range='{}': expected 'start-end'", raw))?;
    let s: usize = a
        .parse()
        .map_err(|e| format!("X-Layer-Range start: {}", e))?;
    let e: usize = b.parse().map_err(|e| format!("X-Layer-Range end: {}", e))?;
    Ok((s, e))
}

fn write_error(stream: &UnixStream, status: u16, msg: &str) {
    eprintln!("[fat-station-uds-zc] error {}: {}", status, msg);
    let body = format!("{{\"error\":{:?}}}", msg);
    // Errors travel inline: we put the JSON in a small shm fd to keep the
    // wire shape uniform. Could be inlined in headers for tiny errors but
    // uniformity beats a special case.
    if let Ok((fd, _)) = ascii_to_fd(body.as_bytes()) {
        let bl = body.len();
        let frame = build_data_frame(
            status,
            &[
                ("Content-Type", "application/json".to_string()),
                ("X-ZC-Body-Bytes", bl.to_string()),
                ("X-ZC-Body-Format", "u8".to_string()),
            ],
        );
        let _ = send_with_fd(stream, &frame, Some(fd.as_raw_fd()));
        drop(fd);
    } else {
        let frame = build_data_frame(status, &[]);
        let _ = send_with_fd(stream, &frame, None);
    }
}

fn ascii_to_fd(data: &[u8]) -> Result<(OwnedFd, usize), String> {
    let n = data.len().max(1);
    let fd = open_anon_shm("zc-err", n).map_err(|e| format!("open shm err: {}", e))?;
    if !data.is_empty() {
        let mut m = unsafe {
            MmapOptions::new()
                .len(n)
                .map_mut(fd.as_raw_fd())
                .map_err(|e| format!("mmap_mut err: {}", e))?
        };
        m.as_mut().copy_from_slice(data);
    }
    Ok((fd, data.len()))
}

fn ok_response(stream: &UnixStream, out: Vec<f32>, request_id: &str, compute_ms: u128) {
    match f32_to_fd(&out) {
        Ok((fd, byte_len)) => {
            let frame = build_data_frame(
                200,
                &[
                    ("Content-Type", "application/octet-stream".to_string()),
                    ("X-Request-Id", request_id.to_string()),
                    ("X-Compute-Ms", compute_ms.to_string()),
                    ("X-ZC-Body-Bytes", byte_len.to_string()),
                    ("X-ZC-Body-Format", "f32".to_string()),
                ],
            );
            if let Err(e) = send_with_fd(stream, &frame, Some(fd.as_raw_fd())) {
                eprintln!("[fat-station-uds-zc] send_with_fd ok: {}", e);
            }
            drop(fd);
        }
        Err(e) => write_error(stream, 500, &format!("alloc out fd: {}", e)),
    }
}

fn handle_health(station: &Station, stream: &UnixStream) {
    let layers = format!("{}-{}", station.layers.0, station.layers.1);
    let vocab = match station.vocab {
        Some((s, e)) => format!("{}-{}", s, e),
        None => "all".to_string(),
    };
    let body = format!(
        "{{\"status\":\"ok\",\"role\":\"{}\",\"layers\":\"{}\",\"vocab\":\"{}\",\"vocab_size\":{},\"hidden_dim\":{},\"transport\":\"uds-zerocopy\"}}",
        station.role.as_str(),
        layers,
        vocab,
        station.vocab_size,
        station.hidden_dim,
    );
    match ascii_to_fd(body.as_bytes()) {
        Ok((fd, byte_len)) => {
            let frame = build_data_frame(
                200,
                &[
                    ("Content-Type", "application/json".to_string()),
                    ("X-ZC-Body-Bytes", byte_len.to_string()),
                    ("X-ZC-Body-Format", "u8".to_string()),
                ],
            );
            let _ = send_with_fd(stream, &frame, Some(fd.as_raw_fd()));
            drop(fd);
        }
        Err(e) => write_error(stream, 500, &e),
    }
}

fn handle_embed(station: &Station, frame: Frame, body_fd: Option<OwnedFd>, stream: &UnixStream) {
    if !matches!(station.role, Role::Entry | Role::Both) {
        return write_error(
            stream,
            404,
            &format!("/embed not available on role={}", station.role.as_str()),
        );
    }
    let request_id = frame.header("X-Request-Id").unwrap_or("no-id").to_string();
    let start_pos = match parse_usize_header(&frame, "X-Position") {
        Ok(v) => v,
        Err(e) => return write_error(stream, 400, &e),
    };
    let body_fd = match body_fd {
        Some(fd) => fd,
        None => return write_error(stream, 400, "missing SCM_RIGHTS body fd"),
    };
    let tokens = match fd_to_u32(&body_fd, frame.body_bytes) {
        Ok(t) => t,
        Err(e) => return write_error(stream, 400, &e),
    };
    let t0 = std::time::Instant::now();
    let result = {
        let mut p = station.pipeline.lock().unwrap();
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            p.embed_chunk(&tokens, start_pos)
        }))
    };
    match result {
        Ok(Ok(out)) => ok_response(stream, out, &request_id, t0.elapsed().as_millis()),
        Ok(Err(e)) => write_error(stream, 500, &format!("embed: {}", e)),
        Err(e) => write_error(
            stream,
            500,
            &format!("embed panic: {:?}", panic_payload(&e)),
        ),
    }
}

fn handle_forward(station: &Station, frame: Frame, body_fd: Option<OwnedFd>, stream: &UnixStream) {
    if matches!(station.role, Role::Cobordism) {
        return write_error(stream, 404, "/forward not available on cobordism");
    }
    let request_id = frame.header("X-Request-Id").unwrap_or("no-id").to_string();
    let start_pos = match parse_usize_header(&frame, "X-Position") {
        Ok(v) => v,
        Err(e) => return write_error(stream, 400, &e),
    };
    let seq_len = match parse_usize_header(&frame, "X-Sequence-Length") {
        Ok(v) => v,
        Err(e) => return write_error(stream, 400, &e),
    };
    let layer_range = match parse_layer_range_header(&frame) {
        Ok(v) => v,
        Err(e) => return write_error(stream, 400, &e),
    };
    let body_fd = match body_fd {
        Some(fd) => fd,
        None => return write_error(stream, 400, "missing SCM_RIGHTS body fd"),
    };
    let residual = match fd_to_f32(&body_fd, frame.body_bytes) {
        Ok(r) => r,
        Err(e) => return write_error(stream, 400, &e),
    };
    if seq_len == 0 || seq_len > NATIVE_BATCH_CAPACITY {
        return write_error(
            stream,
            400,
            &format!("seq_len {} out of (0,{}]", seq_len, NATIVE_BATCH_CAPACITY),
        );
    }
    let t0 = std::time::Instant::now();
    let result = {
        let mut p = station.pipeline.lock().unwrap();
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            p.forward_range_chunk(&residual, layer_range.0, layer_range.1, start_pos, seq_len)
        }))
    };
    match result {
        Ok(Ok(out)) => ok_response(stream, out, &request_id, t0.elapsed().as_millis()),
        Ok(Err(e)) => write_error(stream, 500, &format!("forward: {}", e)),
        Err(e) => write_error(
            stream,
            500,
            &format!("forward panic: {:?}", panic_payload(&e)),
        ),
    }
}

